mapper.select:
SELECT a.id AS rechargeWayId, a.recharge_way_i18 AS rechargeWayName, a.recharge_type_id AS rechargeTypeId, (SELECT recharge_type_i18 FROM system_recharge_type WHERE id = a.recharge_type_id) AS rechargeTypeName, IFNULL(t1.way_fee, a.way_fee) AS depositFee, IFNULL(t1.way_fee_fixed_amount, a.way_fee_fixed_amount) AS wayFeeFixedAmount, IFNULL(t1.fee_type, a.fee_type) AS feeType, a.way_icon AS wayIcon, a.memo AS memo, a.status AS status,
CASE WHEN t1.site_code IS NOT NULL AND t1.site_code != '' THEN t1.created_time ELSE a.updated_time END AS operatorTime,
CASE WHEN t1.site_code IS NOT NULL AND t1.site_code != '' THEN t1.creator ELSE a.creator END AS operator,
CASE WHEN a.id = t1.recharge_way_id THEN 1 ELSE 0 END AS chooseFlag
FROM ( SELECT t.id, t.recharge_way, t.recharge_way_i18, t.recharge_type_id, t.way_fee, t.way_fee_fixed_amount, t.fee_type, t.way_icon, t.memo, t.status, t.sort_order, t.updated_time, t.creator, t.recharge_type_code,
(SELECT COUNT(1) FROM system_recharge_channel src WHERE src.recharge_way_id = t.id) AS channelTotal
FROM system_recharge_way t WHERE t.currency_code = #{vo.currency}
AND t.recharge_type_id = #{vo.rechargeTypeId}
AND t.id = #{vo.rechargeWayId}
AND t.status = #{vo.status}
) a LEFT JOIN site_recharge_way t1 ON a.id = t1.recharge_way_id AND t1.site_code = #{vo.siteCode} where ( a.channelTotal > 0 or a.recharge_type_code = 'manual_recharge') ORDER BY chooseFlag desc, a.status DESC, a.sort_order DESC

SELECT a.id AS id, b.currency_code AS currencyCode, a.recharge_way_id AS rechargeWayId, b.recharge_way_i18 AS rechargeWayI18, b.recharge_type_code AS rechargeTypeCode, b.way_icon AS wayIcon, a.fee_type AS feeType, a.way_fee AS wayFee, a.way_fee_fixed_amount AS wayFeeFixedAmount, a.status AS status, a.sort_order AS sortOrder, a.creator AS creator, a.created_time AS createdTime, a.updater AS updater, a.updated_time AS updatedTime, c.recharge_type_i18 AS rechargeTypeI18, a.vip_grade_use_scope AS vipGradeUseScope FROM site_recharge_way a LEFT JOIN system_recharge_way b ON b.id = a.recharge_way_id LEFT JOIN system_recharge_type c ON c.id = b.recharge_type_id WHERE a.site_code = #{vo.siteCode}
AND c.id = #{vo.rechargeTypeId}
AND b.currency_code = #{vo.currencyCode}
AND b.recharge_way LIKE CONCAT('%', #{vo.rechargeWay}, '%')
AND a.status = #{vo.status}
AND a.fee_type = #{vo.feeType}
ORDER BY a.updated_time DESC

SELECT a.id AS id, b.currency_code AS currencyCode, a.recharge_way_id AS rechargeWayId, b.recharge_way_i18 AS rechargeWayI18, b.recharge_type_code AS rechargeTypeCode, b.way_icon AS wayIcon, a.fee_type AS feeType, a.way_fee AS wayFee, a.way_fee_fixed_amount AS wayFeeFixedAmount, a.status AS status, a.sort_order AS sortOrder, a.creator AS creator, a.created_time AS createdTime, a.updater AS updater, a.updated_time AS updatedTime, c.recharge_type_i18 AS rechargeTypeI18, a.vip_grade_use_scope AS vipGradeUseScope FROM site_recharge_way a LEFT JOIN system_recharge_way b ON b.id = a.recharge_way_id LEFT JOIN system_recharge_type c ON c.id = b.recharge_type_id WHERE a.site_code = #{vo.siteCode}
AND c.id = #{vo.rechargeTypeId}
AND b.currency_code = #{vo.currencyCode}
AND b.recharge_way LIKE CONCAT('%', #{vo.rechargeWay}, '%')
and a.status = #{vo.status}
AND a.fee_type = #{vo.feeType}
ORDER BY a.sort_order ASC

SELECT b.id AS id, b.currency_code AS currencyCode, b.recharge_type_id AS rechargeTypeId, b.recharge_type_code AS rechargeTypeCode, b.recharge_way AS rechargeWay, b.recharge_way_i18 AS rechargeWayI18, b.network_type AS networkType, b.fee_type AS feeType, b.way_fee AS wayFee, b.way_fee_fixed_amount AS wayFeeFixedAmount, b.quick_amount AS quickAmount, b.way_icon AS wayIcon, b.memo AS memo, b.recommend_flag AS recommendFlag, a.vip_grade_use_scope AS vipGradeUseScope FROM site_recharge_way a LEFT JOIN system_recharge_way b ON b.id = a.recharge_way_id LEFT JOIN system_recharge_type c ON c.id = b.recharge_type_id WHERE a.site_code = #{vo.siteCode} AND a.status = 1 AND b.status = 1
AND b.currency_code = #{vo.mainCurrency}
ORDER BY b.recommend_flag DESC, a.sort_order ASC

SELECT b.id AS id, b.currency_code AS currencyCode, b.recharge_type_id AS rechargeTypeId, b.recharge_type_code AS rechargeTypeCode, b.recharge_way AS rechargeWay, b.recharge_way_i18 AS rechargeWayI18, b.network_type AS networkType, b.fee_type AS feeType, b.way_fee AS wayFee, b.way_fee_fixed_amount AS wayFeeFixedAmount, b.quick_amount AS quickAmount, b.way_icon AS wayIcon, b.memo AS memo, b.recommend_flag AS recommendFlag FROM site_recharge_way a LEFT JOIN system_recharge_way b ON b.id = a.recharge_way_id WHERE a.site_code = #{siteCode} AND a.status = 1 AND b.status = 1
AND b.currency_code = #{currencyCode}
AND b.id = #{wayId}
AND b.network_type = #{networkType}
LIMIT 1
